code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { CodeBlock, Chip, createHighlighter } from 'decantr/components';

code.example:
function CodePreviewSplit() {
  const { div, h2, p } = tags;

  const code = `import { tags } from 'decantr/tags';\nimport { Button } from 'decantr/components';\n\nfunction App() {\n  const { div, h1 } = tags;\n  return div({},\n    h1({}, 'Hello World'),\n    Button({ variant: 'primary' }, 'Click me')\n  );\n}`;

  return div({ class: css('_grid _gc1 _lg:gc2 _gap8 _py12 _px6 _aic') },
    div({ class: css('_flex _col _gap4') },
      h2({ class: css('_heading2 d-gradient-text') }, 'Get started in seconds'),
      p({ class: css('_body _fgmuted') }, 'Install, create a component, and ship. No build config, no boilerplate.'),
      div({ class: css('_flex _gap2 _wrap') },
        Chip({}, 'Zero Config'),
        Chip({}, 'Hot Reload'),
        Chip({}, 'Tree Shaking')
      )
    ),
    CodeBlock({ language: 'js', copyable: true, highlight: createHighlighter }, code)
  );
}

